1	package config
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"maps"
7		"slices"
8		"strconv"
9		"strings"
10		gotemplate "text/template"
11	
12		"github.com/dlclark/regexp2/v2"
13		"k8s.io/apimachinery/pkg/types"
14	
15		"github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha2"
16		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
17		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
18		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/shared"
19		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
20		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph"
21		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
22	)
23	
24	var serversTemplate = gotemplate.Must(
25		gotemplate.New("servers").Funcs(gotemplate.FuncMap{
26			"contains": func(str http.LocationType, substr string) bool {
27				return strings.Contains(string(str), substr)
28			},
29			"headerToNginxVar":   headerToNginxVar,
30			"extAuthResponseVar": func(h string) string { return extAuthResponseVarPrefix + headerToNginxVar(h) },
31			"upstreamHTTPVar":    func(h string) string { return upstreamHTTPVarPrefix + headerToNginxVar(h) },
32		}).Parse(serversTemplateText),
33	)
34	
35	// headerToNginxVar converts an HTTP header name to its NGINX variable form.
36	func headerToNginxVar(h string) string {
37		return strings.ToLower(strings.ReplaceAll(h, "-", "_"))
38	}
39	
40	const (
41		// HeaderMatchSeparator is the separator for constructing header-based match for NJS.
42		HeaderMatchSeparator = ":"
43		rootPath             = "/"
44	
45		// extAuthPathHeader is the header name used to pass the original request path to the auth server.
46		extAuthPathHeader = "Path"
47		// extAuthPathValue is the NGINX variable for the original request URI.
48		extAuthPathValue = "$request_uri"
49		// extAuthMethodHeader is the header name used to pass the original request method to the auth server.
50		extAuthMethodHeader = "Method"
51		// extAuthMethodValue is the NGINX variable for the original request method.
52		extAuthMethodValue = "$request_method"
53		// extAuthAuthorizationHeader forward the client's Authorization header to the
54		// auth server.
55		extAuthAuthorizationHeader = "Authorization"
56		// extAuthAuthorizationValue is the NGINX variable for the original request Authorization header.
57		extAuthAuthorizationValue = "$http_authorization"
58		// proxyPassRequestHeadersOff disables forwarding of all client request headers to the proxied server.
59		proxyPassRequestHeadersOff = "off"
60		// httpHeaderVarPrefix is the NGINX variable prefix for accessing request headers.
61		httpHeaderVarPrefix = "$http_"
62		// extAuthResponseVarPrefix is the NGINX variable prefix for storing auth response header values.
63		extAuthResponseVarPrefix = "$ext_auth_response_"
64		// upstreamHTTPVarPrefix is the NGINX variable prefix for accessing upstream response headers.
65		upstreamHTTPVarPrefix = "$upstream_http_"
66		// proxyPassRequestBodyOff disables forwarding the request body to the proxied server.
67		proxyPassRequestBodyOff = "off"
68	
69		// misdirectedRequestSNIVarPrefix is the prefix for the per-port SNI listener ID variable.
70		misdirectedRequestSNIVarPrefix = "$sni_listener_id_"
71		// misdirectedRequestHostVarPrefix is the prefix for the per-port Host listener ID variable.
72		misdirectedRequestHostVarPrefix = "$host_listener_id_"
73	)
74	
75	// misdirectedRequestSNIVar returns the NGINX variable name for the SNI-derived listener ID for a given port.
76	func misdirectedRequestSNIVar(port int32) string {
77		return misdirectedRequestSNIVarPrefix + strconv.Itoa(int(port))
78	}
79	
80	// misdirectedRequestHostVar returns the NGINX variable name for the Host-derived listener ID for a given port.
81	func misdirectedRequestHostVar(port int32) string {
82		return misdirectedRequestHostVarPrefix + strconv.Itoa(int(port))
83	}
