114	func (g GeneratorImpl) executeServers(
115		conf dataplane.Configuration,
116		generator policies.Generator,
117		keepAliveCheck keepAliveChecker,
118	) []executeResult {
119		servers, httpMatchPairs := createServers(conf, generator, keepAliveCheck)
120	
121		serverConfig := http.ServerConfig{
122			Servers:                  servers,
123			IPFamily:                 getIPFamily(conf.BaseHTTPConfig),
124			Plus:                     g.plus,
125			RewriteClientIP:          getRewriteClientIPSettings(conf.BaseHTTPConfig.RewriteClientIPSettings),
126			DisableSNIHostValidation: conf.BaseHTTPConfig.DisableSNIHostValidation,
127		}
128	
129		serverResult := executeResult{
130			dest: httpConfigFile,
131			data: helpers.MustExecuteTemplate(serversTemplate, serverConfig),
132		}
133	
134		// create httpMatchPair conf
135		httpMatchConf, err := json.Marshal(httpMatchPairs)
136		if err != nil {
137			// panic is safe here because we should never fail to marshal the match unless we constructed it incorrectly.
138			panic(fmt.Errorf("could not marshal http match pairs: %w", err))
139		}
140	
141		httpMatchResult := executeResult{
142			dest: httpMatchVarsFile,
143			data: httpMatchConf,
144		}
145	
146		includeFileResults := createIncludeExecuteResultsFromServers(servers)
147	
148		allResults := make([]executeResult, 0, len(includeFileResults)+2)
149		allResults = append(allResults, includeFileResults...)
150		allResults = append(allResults, serverResult, httpMatchResult)
151	
152		return allResults
153	}
