155	// getIPFamily returns whether the server should be configured for IPv4, IPv6, or both.
156	func getIPFamily(baseHTTPConfig dataplane.BaseHTTPConfig) shared.IPFamily {
157		switch baseHTTPConfig.IPFamily {
158		case dataplane.IPv4:
159			return shared.IPFamily{IPv4: true}
160		case dataplane.IPv6:
161			return shared.IPFamily{IPv6: true}
162		}
163	
164		return shared.IPFamily{IPv4: true, IPv6: true}
165	}
