167	func createServers(
168		conf dataplane.Configuration,
169		generator policies.Generator,
170		keepAliveCheck keepAliveChecker,
171	) ([]http.Server, httpMatchPairs) {
172		servers := make([]http.Server, 0, len(conf.HTTPServers)+len(conf.SSLServers))
173		finalMatchPairs := make(httpMatchPairs)
174		sharedTLSPorts := make(map[int32]struct{})
175	
176		for _, tlsServer := range conf.TLSServers {
177			sharedTLSPorts[tlsServer.Port] = struct{}{}
178		}
179	
180		for idx, s := range conf.HTTPServers {
181			serverID := fmt.Sprintf("%d", idx)
182			httpServer, matchPairs := createServer(
183				s,
184				serverID,
185				generator,
186				keepAliveCheck,
187				conf.BaseHTTPConfig.DisableBaseProxySetHeaders,
188			)
189			servers = append(servers, httpServer)
190			maps.Copy(finalMatchPairs, matchPairs)
191		}
192	
193		disableSNI := conf.BaseHTTPConfig.DisableSNIHostValidation
194	
195		for idx, s := range conf.SSLServers {
196			serverID := fmt.Sprintf("SSL_%d", idx)
197	
198			sslServer, matchPairs := createSSLServer(
199				s,
200				serverID,
201				generator,
202				keepAliveCheck,
203				disableSNI,
204				conf.BaseHTTPConfig.DisableBaseProxySetHeaders,
205			)
206			if _, portInUse := sharedTLSPorts[s.Port]; portInUse {
207				sslServer.Listen = getSocketNameHTTPS(s.Port)
208				sslServer.IsSocket = true
209			}
210			servers = append(servers, sslServer)
211			maps.Copy(finalMatchPairs, matchPairs)
212		}
213	
214		return servers, finalMatchPairs
215	}
