217	func createSSLServer(
218		virtualServer dataplane.VirtualServer,
219		serverID string,
220		generator policies.Generator,
221		keepAliveCheck keepAliveChecker,
222		disableSNIHostValidation bool,
223		disableBaseProxySetHeaders []string,
224	) (http.Server, httpMatchPairs) {
225		listen := fmt.Sprint(virtualServer.Port)
226		if virtualServer.IsDefault {
227			server := http.Server{
228				IsDefaultSSL: true,
229				Listen:       listen,
230			}
231			if virtualServer.SSL != nil {
232				server.SSL = buildHTTPSSL(virtualServer.SSL)
233			}
234	
235			return server, nil
236		}
237	
238		locs, matchPairs, grpc := createLocations(
239			&virtualServer,
240			serverID,
241			generator,
242			keepAliveCheck,
243			disableBaseProxySetHeaders,
244		)
245	
246		server := http.Server{
247			ServerName: virtualServer.Hostname,
248			SSL:        buildHTTPSSL(virtualServer.SSL),
249			Locations:  locs,
250			GRPC:       grpc,
251			Listen:     listen,
252		}
253	
254		if !disableSNIHostValidation {
255			server.MisdirectedRequestVars = &http.MisdirectedRequestVars{
256				SNIVar:  misdirectedRequestSNIVar(virtualServer.Port),
257				HostVar: misdirectedRequestHostVar(virtualServer.Port),
258			}
259		}
260	
261		policyIncludes := createIncludesFromPolicyGenerateResult(
262			generator.GenerateForServer(virtualServer.Policies, server),
263		)
264		snippetIncludes := createIncludesFromServerSnippetsFilters(virtualServer)
265	
266		server.Includes = make([]shared.Include, 0, len(policyIncludes)+len(snippetIncludes))
267		server.Includes = append(server.Includes, policyIncludes...)
268		server.Includes = append(server.Includes, snippetIncludes...)
269	
270		return server, matchPairs
271	}
