385	/*
386	There are several different flows of location blocks, depending on the user configuration.
387	The following describes them, with basic location examples.
388	
389	---------------
390	Base case, no HTTP matching conditions or inference extension.
391	
392	External location proxies straight to backend.
393	
394	location /coffee {
395	    proxy_pass http://backend;
396	}
397	---------------
398	HTTP matching conditions.
399	
400	External location calls httpmatch NJS module. The module determines the HTTP request conditions that exist
401	and which backend to use, then redirects to the appropriate internal location.
402	The internal location proxies to the backend.
403	
404	location /coffee {
405	    js_content httpmatches.match; // chooses backend1 or backend2, and redirects to appropriate internal location
406	}
407	location /_ngf-internal-rule0-route0 {
408	    internal;
409	    proxy_pass http://backend1;
410	}
411	location /_ngf-internal-rule1-route0 {
412	    internal;
413	    proxy_pass http://backend2;
414	}
415	---------------
416	Inference extension, no HTTP matching conditions.
417	
418	External location calls inference NJS module. The module gets the AI endpoint to proxy to,
419	then redirects to the internal inference location that proxies to the backend.
420	
421	location /coffee {
422	    set $epp_internal_path /_ngf-internal-proxy-pass-rule0-route0-backend0-inference;
423	    js_content epp.getEndpoint; // gets endpoint and redirects to /_ngf-internal-proxy-pass-rule0-route0-backend0-inference
424	}
425	location /_ngf-internal-proxy-pass-rule0-route0-backend0-inference {
426	    internal;
427	    proxy_pass http://$inference_backend_test_foo_80;
428	}
429	---------------
430	Inference extension with multiple inference backends.
431	
432	location /coffee {
433	    rewrite ^ $inference_backend_group_routeNS__routeName_rule0_pathRule0 last;
434	}
435	
436	location /_ngf-internal-proxy-pass-rule0-route0-backend0-inference {
437	    internal;
438	    proxy_pass http://$inference_backend_test_primary_pool_80;
439	}
440	
441	location /_ngf-internal-test_primary_pool_80-routeNS-routeName-routeRule0-pathRule0 {
442	    internal;
443	    set $epp_internal_path /_ngf-internal-proxy-pass-rule0-route0-backend0-inference;
444	    js_content epp.getEndpoint; // gets endpoint and redirects to /_ngf-internal-proxy-pass-rule0-route0-backend0-inference
445	}
446	
447	location /_ngf-internal-proxy-pass-rule0-route0-backend1-inference {
448	    internal;
449	    proxy_pass http://$inference_backend_test_secondary_pool_80;
450	}
451	
452	location /_ngf-internal-test_secondary_pool_80-routeNS-routeName-routeRule0-pathRule0 {
453	    internal;
454	    set $epp_internal_path /_ngf-internal-proxy-pass-rule0-route0-backend1-inference;
455	    js_content epp.getEndpoint; // gets endpoint and redirects to /_ngf-internal-proxy-pass-rule0-route0-backend1-inference
456	}
457	
458	split_clients $request_id $inference_backend_group_routeNS__routeName_rule0_pathRule0 {
459	    70.00% /_ngf-internal-test_primary_pool_80-routeNS-routeName-routeRule0-pathRule0;
460	    30.00% /_ngf-internal-test_secondary_pool_80-routeNS-routeName-routeRule0-pathRule0;
461	}
462	---------------
463	Inference extension with HTTP matching conditions.
464	
465	External location calls httpmatch NJS module. The module determines the HTTP request conditions that exist
466	and which backend to use, then redirects to the internal inference location. The internal inference
467	location calls the inference NJS module to get the AI endpoint to proxy to, then redirects to the
468	internal location that proxies to the backend.
469	
470	location /coffee {
471	    js_content httpmatches.match; // chooses backend and redirects to appropriate internal inference location
472	}
473	location /_ngf-internal-test_foo_80-routeNS-routeName-routeRule0-pathRule0 {
474	    internal;
475	    set $epp_internal_path /_ngf-internal-proxy-pass-rule0-route0-backend0-inference;
476	    js_content epp.getEndpoint; // redirects to /_ngf-internal-proxy-pass-rule0-route0-backend0-inference
477	}
478	location /_ngf-internal-proxy-pass-rule0-route0-backend0-inference {
479	    internal;
480	    proxy_pass http://$inference_backend_test_foo_80;
481	}
482	---------------
483	Inference extension with multiple backends with HTTP matching conditions.
484	
485	External location calls httpmatch NJS module. The module determines the HTTP request conditions that exist
486	and which backend to use, then redirects to an internal location which will rewrite to another internal inference
487	location based on a split clients variable. That internal inference location calls the inference NJS module
488	to get the AI endpoint to proxy to, then redirects to the internal location that proxies to the backend.
489	
490	location /coffee {
491	    js_content httpmatches.match; // chooses backend and redirects to appropriate internal inference location
492	}
493	
494	location /_ngf-internal-split-clients-rule0-route0-inference  {
495	    internal;
496	    rewrite ^ $inference_backend_group_routeNS__routeName_rule0_pathRule0 last;
497	}
498	
499	location /_ngf-internal-proxy-pass-rule0-route0-backend0-inference {
500	    internal;
501	    proxy_pass http://$inference_backend_test_primary_pool_80;
502	}
503	
504	location /_ngf-internal-test_primary_pool_80-routeNS-routeName-routeRule0-pathRule0 {
505	    internal;
506	    set $epp_internal_path /_ngf-internal-proxy-pass-rule0-route0-backend0-inference;
507	    js_content epp.getEndpoint; // gets endpoint and redirects to /_ngf-internal-proxy-pass-rule0-route0-backend0-inference
508	}
509	
510	location /_ngf-internal-proxy-pass-rule0-route0-backend1-inference {
511	    internal;
512	    proxy_pass http://$inference_backend_test_secondary_pool_80;
513	}
514	
515	location /_ngf-internal-test_secondary_pool_80-routeNS-routeName-routeRule0-pathRule0 {
516	    internal;
517	    set $epp_internal_path /_ngf-internal-proxy-pass-rule0-route0-backend1-inference;
518	    js_content epp.getEndpoint; // gets endpoint and redirects to /_ngf-internal-proxy-pass-rule0-route0-backend1-inference
519	}
520	
521	split_clients $request_id $inference_backend_group_routeNS__routeName_rule0_pathRule0 {
522	    70.00% /_ngf-internal-test_primary_pool_80-routeNS-routeName-routeRule0-pathRule0;
523	    30.00% /_ngf-internal-test_secondary_pool_80-routeNS-routeName-routeRule0-pathRule0;
524	}
525	*/
