527	type httpMatchPairs map[string][]routeMatch
528	
529	func createLocations(
530		server *dataplane.VirtualServer,
531		serverID string,
532		generator policies.Generator,
533		keepAliveCheck keepAliveChecker,
534		disableBaseProxySetHeaders []string,
535	) ([]http.Location, httpMatchPairs, bool) {
536		maxLocs, pathsAndTypes := getMaxLocationCountAndPathMap(server.PathRules)
537		locs := make([]http.Location, 0, maxLocs)
538		matchPairs := make(httpMatchPairs)
539	
540		var rootPathExists bool
541		var grpcServer bool
542	
543		mirrorPathToPercentage := extractMirrorTargetsWithPercentages(server.PathRules)
544	
545		for pathRuleIdx, rule := range server.PathRules {
546			if !rootPathExists && matchesRootPath(rule) {
547				rootPathExists = true
548			}
549	
550			if rule.GRPC {
551				grpcServer = true
552			}
553	
554			mirrorPercentage := mirrorPathToPercentage[rule.Path]
555			extLocations := initializeExternalLocations(rule, pathsAndTypes)
556			for i := range extLocations {
557				extLocations[i].Includes = createIncludesFromPolicyGenerateResult(
558					generator.GenerateForLocation(rule.Policies, extLocations[i]),
559				)
560			}
561	
562			switch {
563			case !needsInternalLocationsForMatches(rule) && !rule.HasInferenceBackends:
564				locs = append(locs, updateExternalLocationsForRule(
565					serverID,
566					pathRuleIdx,
567					rule,
568					extLocations,
569					server.Port,
570					keepAliveCheck,
571					disableBaseProxySetHeaders,
572					mirrorPercentage)...,
573				)
574			case needsInternalLocationsForMatches(rule):
575				internalLocations, matches := createInternalLocationsForRule(
576					serverID,
577					pathRuleIdx,
578					rule,
579					generator,
580					server.Port,
581					keepAliveCheck,
582					disableBaseProxySetHeaders,
583					mirrorPercentage,
584				)
585				httpMatchKey := serverID + "_" + strconv.Itoa(pathRuleIdx)
586				for i := range extLocations {
587					// FIXME(sberman): De-dupe matches and associated locations
588					// so we don't need nginx/njs to perform unnecessary matching.
589					// https://github.com/nginx/nginx-gateway-fabric/issues/662
590					extLocations[i].HTTPMatchKey = httpMatchKey
591					matchPairs[extLocations[i].HTTPMatchKey] = matches
592				}
593				locs = append(locs, extLocations...)
594				locs = append(locs, internalLocations...)
595			case rule.HasInferenceBackends:
596				locs = append(locs, createInferenceLocationsForRule(
597					serverID,
598					pathRuleIdx,
599					rule,
600					extLocations,
601					generator,
602					server.Port,
603					keepAliveCheck,
604					disableBaseProxySetHeaders,
605					mirrorPercentage)...,
606				)
607			}
608		}
609	
610		locs = append(locs, createOIDCLocations(server.PathRules)...)
611	
612		if !rootPathExists {
613			locs = append(locs, createDefaultRootLocation())
614		}
615	
616		// Add internal JWKS locations for remote JWT authentication
617		locs = append(locs, extractUniqueJWKSLocations(locs)...)
618	
619		// Add internal auth_request locations for ExternalAuth filters
620		locs = append(locs, extractExternalAuthInternalLocations(locs)...)
621	
622		return locs, matchPairs, grpcServer
623	}
624	
625	func updateExternalLocationsForRule(
626		serverID string,
627		pathRuleIdx int,
628		rule dataplane.PathRule,
629		extLocations []http.Location,
630		port int32,
631		keepAliveCheck keepAliveChecker,
632		disableBaseProxySetHeaders []string,
633		mirrorPercentage *float64,
634	) []http.Location {
635		for matchRuleIndex, r := range rule.MatchRules {
636			extLocations = updateLocations(
637				serverID,
638				pathRuleIdx,
639				matchRuleIndex,
640				r,
641				rule,
642				extLocations,
643				port,
644				keepAliveCheck,
645				disableBaseProxySetHeaders,
646				mirrorPercentage,
647			)
648		}
649	
650		return extLocations
651	}
652	
653	func createInternalLocationsForRule(
654		serverID string,
655		pathRuleIdx int,
656		rule dataplane.PathRule,
657		generator policies.Generator,
658		port int32,
659		keepAliveCheck keepAliveChecker,
660		disableBaseProxySetHeaders []string,
661		mirrorPercentage *float64,
662	) ([]http.Location, []routeMatch) {
663		// Calculate the exact capacity needed
664		capacity := 0
665		for _, r := range rule.MatchRules {
666			if !rule.HasInferenceBackends {
667				capacity++ // intLocation (always created for non-inference)
668			} else {
669				// For inference backends with matches
670				if len(r.BackendGroup.Backends) > 1 {
671					capacity++ // intSplitClientsLocation (created for multiple backends)
672				}
673	
674				capacity += len(r.BackendGroup.Backends) * 2 // intEPPLocation and intProxyPassLocation per backend
675			}
676		}
677	
678		internalLocations := make([]http.Location, 0, capacity)
679		matches := make([]routeMatch, 0, len(rule.MatchRules))
680	
681		// If there are multiple matches on a single route rule, they will share the same intEPPLocation and
682		// intProxyPassLocation. To avoid creating duplicates, we track the unique names here.
683		uniqueEPPNameMap := make(map[string]struct{})
684	
685		for matchRuleIdx, r := range rule.MatchRules {
686			var intLocation http.Location
687			var match routeMatch
688			skipMatch := false
689	
690			if !rule.HasInferenceBackends {
691				intLocation, match = initializeInternalMatchLocation(pathRuleIdx, matchRuleIdx, r.Match, rule.GRPC)
692				intLocation.Includes = createIncludesFromPolicyGenerateResult(
693					generator.GenerateForInternalLocation(rule.Policies),
694				)
695				intLocation = updateLocation(
696					r,
697					rule,
698					intLocation,
699					port,
700					keepAliveCheck,
701					disableBaseProxySetHeaders,
702					mirrorPercentage,
703					serverID,
704					matchRuleIdx,
705					pathRuleIdx,
706				)
707				internalLocations = append(internalLocations, intLocation)
708			} else {
709				// If there are multiple inference backends, we need 4 locations:
710				// 1. (external location) external match location which redirects to split clients location
711				// 2. (intSplitClientsLocation) internal split clients location which rewrites to internal inference
712				// 	  location based on SC variable
713				// 3. (intEPPLocation) internal inference location which calls the EPP NJS module to get endpoint and
714				// 	  redirects to final internal location
715				// 4. (intProxyPassLocation) final internal inference location which proxy_passes to backend
716				//
717				// The match needs to point to the internal split clients location (intSplitClientsLocation)
718				//
719				// If there is only one inference backend, we need 3 locations:
720				// 1. (external location) external match location which redirects to internal inference location
721				// 2. (intEPPLocation) internal inference location which calls the EPP NJS module to get endpoint and
722				//    redirects to final internal location
723				// 3. (intProxyPassLocation) final internal inference location which proxy_passes to backend
724				//
725				// The match needs to point to the internal inference location which calls the EPP NJS module (intEPPLocation)
726	
727				var intEPPLocation http.Location
728				for backendIdx, b := range r.BackendGroup.Backends {
729					intProxyPassLocation := initializeInternalInferenceProxyPassLocation(pathRuleIdx, matchRuleIdx, backendIdx)
730					intProxyPassLocation.Includes = createIncludesFromPolicyGenerateResult(
731						generator.GenerateForInternalLocation(rule.Policies),
732					)
733	
734					// Since we are creating a separate intProxyPassLocation per backend,
735					// we need to update the rule to only have that backend for the location.
736					// This ensures the correct name gets generated to correlate with the split clients generation.
737					// If there is only one backend, this is effectively a no-op.
738					tempRule := dataplane.MatchRule{
739						Source:  r.Source,
740						Match:   r.Match,
741						Filters: r.Filters,
742						BackendGroup: dataplane.BackendGroup{
743							Source:      r.BackendGroup.Source,
744							RuleIdx:     r.BackendGroup.RuleIdx,
745							PathRuleIdx: r.BackendGroup.PathRuleIdx,
746							Backends:    []dataplane.Backend{b}, // Only include the current backend
747						},
748					}
749					intProxyPassLocation = updateLocation(
750						tempRule,
751						rule,
752						intProxyPassLocation,
753						port,
754						keepAliveCheck,
755						disableBaseProxySetHeaders,
756						mirrorPercentage,
757						serverID,
758						matchRuleIdx,
759						pathRuleIdx,
760					)
761	
762					intEPPLocation = initializeInternalInferenceEPPLocation(
763						b,
764						r.BackendGroup.Source,
765						r.BackendGroup.RuleIdx,
766						r.BackendGroup.PathRuleIdx,
767					)
768					intEPPLocation.Includes = createIncludesFromPolicyGenerateResult(
769						generator.GenerateForInternalLocation(rule.Policies),
770					)
771	
772					mapKey := intEPPLocation.Path // Use this as the key to detect duplicates
773	
774					// The only time this happens is on a single route rule with multiple matches with the same path.
775					// In this case, we only need to create one set of internal locations, and can skip the duplicate matches.
776					if _, exists := uniqueEPPNameMap[mapKey]; exists {
777						skipMatch = true
778						break
779					}
780					uniqueEPPNameMap[mapKey] = struct{}{}
781					// we only append intEPPLocation and intProxyPassLocation once per unique intEPPLocation name
782					internalLocations = append(internalLocations, intProxyPassLocation)
783	
784					if b.EndpointPickerConfig != nil && b.EndpointPickerConfig.EndpointPickerRef != nil {
785						eppHost, portNum := extractEPPConfig(b)
786						intEPPLocation = setLocationEPPConfig(intEPPLocation, intProxyPassLocation.Path, eppHost, portNum)
787						internalLocations = append(internalLocations, intEPPLocation)
788					}
789				}
790	
791				// skip adding match and creating split clients location if it's a duplicate intEPPLocation.Path
792				if skipMatch {
793					continue
794				}
795	
796				if len(r.BackendGroup.Backends) > 1 {
797					intSplitClientsLocation := initializeInternalInferenceSplitClientsLocation(pathRuleIdx, matchRuleIdx)
798					intSplitClientsLocation.Includes = createIncludesFromPolicyGenerateResult(
799						generator.GenerateForInternalLocation(rule.Policies),
800					)
801	
802					splitClientsVariableName := createInferenceSplitClientsVariableName(
803						convertStringToSafeVariableName(r.BackendGroup.Name()),
804					)
805					intSplitClientsLocation.Rewrites = append(intSplitClientsLocation.Rewrites,
806						fmt.Sprintf("^ $%s last", splitClientsVariableName))
807	
808					internalLocations = append(internalLocations, intSplitClientsLocation)
809	
810					match = createRouteMatch(r.Match, intSplitClientsLocation.Path)
811				} else {
812					match = createRouteMatch(r.Match, intEPPLocation.Path)
813				}
814			}
815	
816			matches = append(matches, match)
817		}
818	
819		return internalLocations, matches
820	}
