822	func createInferenceLocationsForRule(
823		serverID string,
824		pathRuleIdx int,
825		rule dataplane.PathRule,
826		extLocations []http.Location,
827		generator policies.Generator,
828		port int32,
829		keepAliveCheck keepAliveChecker,
830		disableBaseProxySetHeaders []string,
831		mirrorPercentage *float64,
832	) []http.Location {
833		capacity := len(extLocations)
834	
835		for _, r := range rule.MatchRules {
836			for _, b := range r.BackendGroup.Backends {
837				capacity++ // intProxyPassLocation (always created)
838	
839				// intEPPLocation (created only for multiple backends with EPP config)
840				if len(r.BackendGroup.Backends) > 1 &&
841					b.EndpointPickerConfig != nil &&
842					b.EndpointPickerConfig.EndpointPickerRef != nil {
843					capacity++ // intEPPLocation
844				}
845			}
846		}
847	
848		locs := make([]http.Location, 0, capacity)
849	
850		// There will only be one rule.MatchRules, since if there are multiple, createInternalLocationsForRule
851		// would have been called instead.
852		for matchRuleIdx, r := range rule.MatchRules {
853			// If there are multiple inference backends, we need 3 locations:
854			// 1. (external location) external location which rewrites to the EPP internal location based on a
855			//    split clients variable
856			// 2. (intEPPLocation) internal inference location which calls the EPP NJS module to get endpoint
857			//    and redirects to final internal location
858			// 3. (intProxyPassLocation) final internal inference location which proxy_passes to backend
859			//
860			// If there is only one inference backend, we need 2 locations:
861			// 1. (external location) external location which calls the EPP NJS module to get endpoint and redirects
862			//    to internal inference location
863			// 2. (intProxyPassLocation) final internal inference location which proxy_passes to backend
864	
865			if len(r.BackendGroup.Backends) > 1 {
866				splitClientsVariableName := createInferenceSplitClientsVariableName(
867					convertStringToSafeVariableName(r.BackendGroup.Name()),
868				)
869				for i := range extLocations {
870					extLocations[i].Rewrites = append(extLocations[i].Rewrites, fmt.Sprintf("^ $%s last", splitClientsVariableName))
871					extLocations[i].Type = http.ExternalLocationType
872				}
873			}
874	
875			for backendIdx, b := range r.BackendGroup.Backends {
876				intProxyPassLocation := initializeInternalInferenceProxyPassLocation(pathRuleIdx, matchRuleIdx, backendIdx)
877				intProxyPassLocation.Includes = createIncludesFromPolicyGenerateResult(
878					generator.GenerateForInternalLocation(rule.Policies),
879				)
880	
881				// Since we are creating a separate intProxyPassLocation per backend,
882				// we need to update the rule to only have that backend for the location.
883				// This ensures the correct name gets generated to correlate with the split clients generation.
884				// If there is only one backend, this is effectively a no-op.
885				tempRule := dataplane.MatchRule{
886					Source:  r.Source,
887					Match:   r.Match,
888					Filters: r.Filters,
889					BackendGroup: dataplane.BackendGroup{
890						Source:      r.BackendGroup.Source,
891						RuleIdx:     r.BackendGroup.RuleIdx,
892						PathRuleIdx: r.BackendGroup.PathRuleIdx,
893						Backends:    []dataplane.Backend{b}, // Only include the current backend
894					},
895				}
896				intProxyPassLocation = updateLocation(
897					tempRule,
898					rule,
899					intProxyPassLocation,
900					port,
901					keepAliveCheck,
902					disableBaseProxySetHeaders,
903					mirrorPercentage,
904					serverID,
905					matchRuleIdx,
906					pathRuleIdx,
907				)
908				locs = append(locs, intProxyPassLocation)
909	
910				if b.EndpointPickerConfig != nil && b.EndpointPickerConfig.EndpointPickerRef != nil {
911					eppHost, portNum := extractEPPConfig(b)
912	
913					if len(r.BackendGroup.Backends) > 1 {
914						intEPPLocation := initializeInternalInferenceEPPLocation(
915							b,
916							r.BackendGroup.Source,
917							r.BackendGroup.RuleIdx,
918							r.BackendGroup.PathRuleIdx,
919						)
920						intEPPLocation.Includes = createIncludesFromPolicyGenerateResult(
921							generator.GenerateForInternalLocation(rule.Policies),
922						)
923						intEPPLocation = setLocationEPPConfig(intEPPLocation, intProxyPassLocation.Path, eppHost, portNum)
924						locs = append(locs, intEPPLocation)
925					} else {
926						for i := range extLocations {
927							extLocations[i] = setLocationEPPConfig(extLocations[i], intProxyPassLocation.Path, eppHost, portNum)
928						}
929					}
930				}
931			}
932		}
933		locs = append(locs, extLocations...)
934	
935		return locs
936	}
