1101	func getLocationTypeForPathRule(rule dataplane.PathRule) http.LocationType {
1102		if needsInternalLocationsForMatches(rule) {
1103			return http.RedirectLocationType
1104		}
1105	
1106		if rule.HasInferenceBackends {
1107			return http.InferenceExternalLocationType
1108		}
1109	
1110		return http.ExternalLocationType
1111	}
