1238	func updateLocationAuthenticationFilter(
1239		location http.Location,
1240		authenticationFilter *dataplane.AuthenticationFilter,
1241	) http.Location {
1242		if authenticationFilter == nil {
1243			return location
1244		}
1245	
1246		if authenticationFilter.Basic != nil {
1247			id := dataplane.GenerateAuthBasicFileID(
1248				authenticationFilter.Basic.SecretNamespace,
1249				authenticationFilter.Basic.SecretName,
1250			)
1251			location.AuthBasic = &http.AuthBasic{
1252				Realm: authenticationFilter.Basic.Realm,
1253				File:  generateAuthFileName(id),
1254			}
1255		}
1256	
1257		if authenticationFilter.JWT != nil {
1258			location.AuthJWT = getAuthJWTLocationConfig(authenticationFilter.JWT)
1259		}
1260	
1261		if authenticationFilter.OIDC != nil && authenticationFilter.OIDC.Provider != nil {
1262			location.AuthOIDC = getAuthOIDCLocationConfig(authenticationFilter.OIDC)
1263		}
1264	
1265		return location
1266	}
