1268	// getAuthJWTLocationConfig returns the AuthJWT configuration for a given JWT authentication filter.
1269	// It handles both remote and local JWT configurations.
1270	func getAuthJWTLocationConfig(jwtAuthFilter *dataplane.AuthJWT) *http.AuthJWT {
1271		jwt := &http.AuthJWT{
1272			Realm:    jwtAuthFilter.Realm,
1273			KeyCache: jwtAuthFilter.KeyCache,
1274			Leeway:   jwtAuthFilter.Leeway,
1275		}
1276	
1277		if jwtAuthFilter.Remote != nil {
1278			remote := &http.AuthJWTRemote{
1279				URI:  jwtAuthFilter.Remote.URI,
1280				Path: jwtAuthFilter.Remote.Path,
1281			}
1282	
1283			if jwtAuthFilter.Remote.CACertBundlePath != "" {
1284				remote.TrustedCertificate = generateCertBundleFileName(
1285					jwtAuthFilter.Remote.CACertBundlePath,
1286				)
1287			} else {
1288				remote.TrustedCertificate = dataplane.AlpineSSLRootCAPath
1289			}
1290	
1291			jwt.Remote = remote
1292		} else {
1293			id := dataplane.GenerateAuthJWTFileID(
1294				jwtAuthFilter.SecretNamespace,
1295				jwtAuthFilter.SecretName,
1296			)
1297			jwt.File = generateAuthFileName(id)
1298		}
1299	
1300		if jwtAuthFilter.AuthRequireVariable != "" {
1301			jwt.AuthZConfig = &http.AuthZConfig{
1302				AuthRequire: jwtAuthFilter.AuthRequireVariable,
1303			}
1304		}
1305		if len(jwtAuthFilter.AuthZProxySetHeaders) > 0 {
1306			proxySetHeaders := make([]http.Header, 0, len(jwtAuthFilter.AuthZProxySetHeaders))
1307			for _, psh := range jwtAuthFilter.AuthZProxySetHeaders {
1308				proxySetHeaders = append(proxySetHeaders, http.Header{
1309					Name:  psh.Name,
1310					Value: psh.Value,
1311				})
1312			}
1313			if jwt.AuthZConfig == nil {
