1371	// extractExternalAuthInternalLocations extracts unique internal auth_request locations from a list of locations.
1372	func extractExternalAuthInternalLocations(locations []http.Location) []http.Location {
1373		seen := make(map[string]struct{})
1374		var result []http.Location
1375	
1376		for _, loc := range locations {
1377			if loc.AuthExternalRequest == nil {
1378				continue
1379			}
1380			path := loc.AuthExternalRequest.InternalPath
1381			if _, exists := seen[path]; exists {
1382				continue
1383			}
1384			seen[path] = struct{}{}
1385	
1386			ar := loc.AuthExternalRequest
1387			proxyPass := generateProtocolString(ar.ProxySSLVerify, false) + "://" + ar.UpstreamName
1388			if ar.PathPrefix != "" {
1389				proxyPass += ar.PathPrefix
1390			}
1391	
1392			headers := []http.Header{
1393				{Name: "Host", Value: "$gw_api_compliant_host"},
1394				{Name: extAuthPathHeader, Value: extAuthPathValue},
1395				{Name: extAuthMethodHeader, Value: extAuthMethodValue},
1396				{Name: extAuthAuthorizationHeader, Value: extAuthAuthorizationValue},
1397			}
1398			for _, h := range ar.AllowedRequestHeaders {
1399				headers = append(headers, http.Header{Name: h, Value: httpHeaderVarPrefix + headerToNginxVar(h)})
1400			}
1401	
1402			var proxyPassBody string
1403			if !ar.ForwardBody {
1404				proxyPassBody = proxyPassRequestBodyOff
1405			}
1406			authLoc := http.Location{
1407				Path:                    path,
1408				Type:                    http.InternalLocationType,
1409				ProxyPass:               proxyPass,
1410				ProxySetHeaders:         headers,
1411				ProxySSLVerify:          ar.ProxySSLVerify,
1412				ProxyPassRequestBody:    proxyPassBody,
1413				ProxyPassRequestHeaders: proxyPassRequestHeadersOff,
1414			}
1415			result = append(result, authLoc)
1416		}
