1542	func updateLocationProxySettings(
1543		location http.Location,
1544		matchRule dataplane.MatchRule,
1545		grpc bool,
1546		inferenceBackend bool,
1547		keepAliveCheck keepAliveChecker,
1548		disableBaseProxySetHeaders []string,
1549	) http.Location {
1550		location.ProxyHTTPVersion = resolveProxyHTTPVersion(matchRule.BackendGroup.Backends, grpc)
1551	
1552		extraHeaders := make([]http.Header, 0, 3)
1553	
1554		switch {
1555		case location.ProxyHTTPVersion == "2":
1556		case grpc:
1557			extraHeaders = append(extraHeaders, grpcAuthorityHeader)
1558		default:
1559			extraHeaders = append(extraHeaders, httpUpgradeHeader)
1560			extraHeaders = append(extraHeaders, getConnectionHeader(keepAliveCheck, matchRule.BackendGroup.Backends))
1561		}
1562	
1563		// Check if we have an ExternalName service backend
1564		var externalHostname string
1565		for _, backend := range matchRule.BackendGroup.Backends {
1566			if backend.ExternalHostname != "" {
1567				externalHostname = backend.ExternalHostname
1568				break
1569			}
1570		}
1571	
1572		baseProxySetHeaders := createBaseProxySetHeaders(externalHostname, extraHeaders...)
1573		baseProxySetHeaders = filterBaseProxySetHeaders(baseProxySetHeaders, disableBaseProxySetHeaders)
1574	
1575		proxySetHeaders := generateProxySetHeaders(
1576			&matchRule.Filters,
1577			baseProxySetHeaders,
1578		)
1579		responseHeaders := generateResponseHeaders(&matchRule.Filters)
1580	
1581		location.ProxySetHeaders = proxySetHeaders
1582		location.ProxySSLVerify = createProxyTLSFromBackends(matchRule.BackendGroup.Backends)
1583		proxyPass := createProxyPass(
1584			matchRule.BackendGroup,
1585			matchRule.Filters.RequestURLRewrite,
1586			generateProtocolString(location.ProxySSLVerify, grpc),
1587			grpc,
1588			inferenceBackend,
1589			location.Type,
1590		)
1591	
1592		location.ResponseHeaders = responseHeaders
1593		location.ProxyPass = proxyPass
1594		location.GRPC = grpc
1595	
1596		return location
1597	}
