1678	func createProxyTLSFromBackends(backends []dataplane.Backend) *http.ProxySSLVerify {
1679		if len(backends) == 0 {
1680			return nil
1681		}
1682		for _, b := range backends {
1683			proxyVerify := createProxySSLVerify(b.VerifyTLS)
1684			if proxyVerify != nil {
1685				// If any backend has a backend TLS policy defined, then we use that for the proxy SSL verification.
1686				// We require that all backends in a group have the same backend TLS policy.
1687				// Verification that all backends in a group have the same backend TLS policy is done in the graph package.
1688				return proxyVerify
1689			}
1690		}
1691		return nil
1692	}
