1694	func createProxySSLVerify(v *dataplane.VerifyTLS) *http.ProxySSLVerify {
1695		if v == nil {
1696			return nil
1697		}
1698		var trustedCert string
1699		if v.CertBundleID != "" {
1700			trustedCert = generateCertBundleFileName(v.CertBundleID)
1701		} else {
1702			trustedCert = v.RootCAPath
1703		}
1704		return &http.ProxySSLVerify{
1705			TrustedCertificate: trustedCert,
1706			Name:               v.Hostname,
1707		}
1708	}
