1710	func createReturnAndRewriteConfigForRedirectFilter(
1711		filter *dataplane.HTTPRequestRedirectFilter,
1712		listenerPort int32,
1713		pathRule dataplane.PathRule,
1714	) (*http.Return, *rewriteConfig) {
1715		if filter == nil {
1716			return nil, nil
1717		}
1718	
1719		hostname := "$host"
1720		if filter.Hostname != nil {
1721			hostname = *filter.Hostname
1722		}
1723	
1724		code := http.StatusFound
1725		if filter.StatusCode != nil {
1726			code = http.StatusCode(*filter.StatusCode)
1727		}
1728	
1729		port := listenerPort
1730		if filter.Port != nil {
1731			port = *filter.Port
1732		}
1733	
1734		hostnamePort := fmt.Sprintf("%s:%d", hostname, port)
1735	
1736		scheme := "$scheme"
1737		if filter.Scheme != nil {
1738			scheme = *filter.Scheme
1739			// Don't specify the port in the return url if the scheme is
1740			// well known and the port is already set to the correct well known port
1741			if (port == 80 && scheme == "http") || (port == 443 && scheme == "https") {
1742				hostnamePort = hostname
1743			}
1744			if filter.Port == nil {
1745				// Don't specify the port in the return url if the scheme is
1746				// well known and the port is not specified by the user
1747				if scheme == "http" || scheme == "https" {
1748					hostnamePort = hostname
1749				}
1750			}
1751		}
1752	
1753		body := fmt.Sprintf("%s://%s$request_uri", scheme, hostnamePort)
1754	
1755		rewrites := &rewriteConfig{}
1756		if filter.Path != nil {
1757			mainRewrite := createMainRewriteForFilters(filter.Path, pathRule)
1758			if mainRewrite == "" {
1759				// Invalid configuration for the rewrite filter
1760				return nil, nil
1761			}
1762			rewrites.MainRewrite = mainRewrite
1763			body = fmt.Sprintf("%s://%s$uri$is_args$args", scheme, hostnamePort)
1764		}
1765	
1766		return &http.Return{
1767			Code: code,
1768			Body: body,
1769		}, rewrites
1770	}
1771	
1772	func createMainRewriteForFilters(pathModifier *dataplane.HTTPPathModifier, pathRule dataplane.PathRule) string {
1773		var mainRewrite string
1774		switch pathModifier.Type {
1775		case dataplane.ReplaceFullPath:
1776			mainRewrite = fmt.Sprintf("^ %s", pathModifier.Replacement)
1777		case dataplane.ReplacePrefixMatch:
1778			// ReplacePrefixMatch is only compatible with a PathPrefix HTTPRouteMatch.
1779			// ReplaceFullPath is compatible with PathTypeExact/PathTypePrefix/PathTypeRegularExpression HTTPRouteMatch.
1780			// see https://gateway-api.sigs.k8s.io/reference/spec/?h=replaceprefixmatch#httppathmodifier
1781			if pathRule.PathType != dataplane.PathTypePrefix {
1782				return ""
1783			}
1784	
1785			filterPrefix := pathModifier.Replacement
1786			if filterPrefix == "" {
1787				filterPrefix = "/"
1788			}
1789	
1790			// Escape $ in the path so it is treated as a literal character in the PCRE regex,
1791			// not as an end-of-string anchor. This matters when the route path contains a $ sign
1792			// (e.g. /$coffee), which is valid in a Gateway API path but has special meaning in PCRE.
1793			escapedPath := strings.ReplaceAll(pathRule.Path, "$", `\$`)
1794	
1795			// capture everything following the configured prefix up to the first ?, if present.
1796			regex := fmt.Sprintf("^%s([^?]*)?", escapedPath)
1797			// replace the configured prefix with the filter prefix, append the captured segment,
1798			// and include the request arguments stored in nginx variable $args.
1799			// https://nginx.org/en/docs/http/ngx_http_core_module.html#var_args
1800			replacement := fmt.Sprintf("%s$1?$args?", filterPrefix)
1801	
1802			// if configured prefix does not end in /, but replacement prefix does end in /,
1803			// then make sure that we *require* but *don't capture* a trailing slash in the request,
1804			// otherwise we'll get duplicate slashes in the full replacement
1805			if strings.HasSuffix(filterPrefix, "/") && !strings.HasSuffix(pathRule.Path, "/") {
1806				regex = fmt.Sprintf("^%s(?:/([^?]*))?", escapedPath)
1807			}
1808	
1809			// if configured prefix ends in / we won't capture it for a request (since it's not in the regex),
1810			// so append it to the replacement prefix if the replacement prefix doesn't already end in /
1811			if strings.HasSuffix(pathRule.Path, "/") && !strings.HasSuffix(filterPrefix, "/") {
1812				replacement = fmt.Sprintf("%s/$1?$args?", filterPrefix)
1813			}
1814	
1815			mainRewrite = fmt.Sprintf("%s %s", regex, replacement)
1816		}
1817	
1818		return mainRewrite
1819	}
1820	
1821	func createRewritesValForRewriteFilter(
1822		filter *dataplane.HTTPURLRewriteFilter,
1823		pathRule dataplane.PathRule,
1824	) *rewriteConfig {
1825		if filter == nil {
1826			return nil
1827		}
1828	
1829		rewrites := &rewriteConfig{}
1830		if filter.Path != nil {
1831			rewrites.InternalRewrite = "^ $request_uri"
1832	
1833			mainRewrite := createMainRewriteForFilters(filter.Path, pathRule)
1834			if mainRewrite == "" {
1835				// Invalid configuration for the rewrite filter
1836				return nil
1837			}
1838			// For URLRewriteFilter, add "break" to prevent further processing of the request.
1839			rewrites.MainRewrite = fmt.Sprintf("%s break", mainRewrite)
1840		}
1841	
1842		return rewrites
1843	}
