1845	// routeMatch is an internal representation of an HTTPRouteMatch.
1846	// This struct is stored as a key-value pair in /etc/nginx/conf.d/matches.json with a key for the route's path.
1847	// The NJS httpmatches module will look up key specified in the nginx location on the request object
1848	// and compare the request against the Method, Headers, and QueryParams contained in routeMatch.
1849	// If the request satisfies the routeMatch, NGINX will redirect the request to the location RedirectPath.
1850	type routeMatch struct {
1851		// Method is the HTTPMethod of the HTTPRouteMatch.
1852		Method string `json:"method,omitempty"`
1853		// RedirectPath is the path to redirect the request to if the request satisfies the match conditions.
1854		RedirectPath string `json:"redirectPath,omitempty"`
1855		// Headers is a list of HTTPHeaders name value pairs with the format "{name}:{value}".
1856		Headers []string `json:"headers,omitempty"`
1857		// QueryParams is a list of HTTPQueryParams name value pairs with the format "{name}={value}".
1858		QueryParams []string `json:"params,omitempty"`
1859		// Any represents a match with no match conditions.
1860		Any bool `json:"any,omitempty"`
1861	}
1862	
1863	func createRouteMatch(match dataplane.Match, redirectPath string) routeMatch {
1864		hm := routeMatch{
1865			RedirectPath: redirectPath,
1866		}
1867	
1868		if isPathOnlyMatch(match) {
1869			hm.Any = true
1870			return hm
1871		}
1872	
1873		if match.Method != nil {
1874			hm.Method = *match.Method
1875		}
1876	
1877		if match.Headers != nil {
1878			headers := make([]string, 0, len(match.Headers))
1879			headerNames := make(map[string]struct{})
1880	
1881			for _, h := range match.Headers {
1882				// duplicate header names are not permitted by the spec
1883				// only configure the first entry for every header name (case-insensitive)
1884				lowerName := strings.ToLower(h.Name)
1885				if _, ok := headerNames[lowerName]; !ok {
1886					headers = append(headers, createHeaderKeyValString(h))
1887					headerNames[lowerName] = struct{}{}
1888				}
1889			}
1890			hm.Headers = headers
1891		}
1892	
1893		if match.QueryParams != nil {
1894			params := make([]string, 0, len(match.QueryParams))
1895	
1896			for _, p := range match.QueryParams {
1897				params = append(params, createQueryParamKeyValString(p))
1898			}
1899			hm.QueryParams = params
1900		}
1901	
1902		return hm
1903	}
1904	
1905	// The name, match type and values are delimited by "=".
1906	// A name, match type and value can always be recovered using strings.SplitN(arg,"=", 3).
1907	// Query Parameters are case-sensitive so case is preserved.
1908	// The match type is optional and defaults to "Exact".
1909	func createQueryParamKeyValString(p dataplane.HTTPQueryParamMatch) string {
1910		return p.Name + "=" + string(p.Type) + "=" + p.Value
1911	}
1912	
1913	// The name, match type and values are delimited by ":".
1914	// A name, match type and value can always be recovered using strings.Split(arg, ":").
1915	// Header names are case-insensitive and header values are case-sensitive.
1916	// The match type is optional and defaults to "Exact".
1917	// Ex. foo:bar == FOO:bar, but foo:bar != foo:BAR,
1918	// We preserve the case of the name here because NGINX allows us to look up the header names in a case-insensitive
1919	// manner.
