1930		filter *dataplane.HTTPURLRewriteFilter,
1931		protocol string,
1932		grpc bool,
1933		inferenceBackend bool,
1934		locationType http.LocationType,
1935	) string {
1936		var requestURI string
1937		// Only append $request_uri for internal locations where the URI has been changed by an
1938		// internal redirect and needs to be restored to the original client request URI.
1939		// For external locations, nginx's default behavior of using the processed URI is correct
1940		// and also works properly with SSI (server-side includes).
1941		if !grpc && locationType == http.InternalLocationType {
