1947		backendName := backendGroupName(backendGroup)
1948	
1949		if inferenceBackend && !strings.Contains(backendName, invalidBackendRef) {
1950			backendVarName := strings.ReplaceAll(backendName, "-", "_")
1951			return "http://$inference_backend_" + backendVarName + requestURI
1952		}
