1979	) []http.Header {
1980		if filters != nil && filters.RequestURLRewrite != nil && filters.RequestURLRewrite.Hostname != nil {
1981			for i, header := range baseHeaders {
1982				if header.Name == "Host" {
1983					baseHeaders[i].Value = *filters.RequestURLRewrite.Hostname
