2003			proxySetHeaders = append(proxySetHeaders, setHeaders...)
2004		}
2005		// If the value of a header field is an empty string then this field will not be passed to a proxied server
2006		for _, h := range headerFilter.Remove {
2007			proxySetHeaders = append(proxySetHeaders, http.Header{
2008				Name:  h,
2009				Value: "",
2010			})
2011		}
2012	
2013		for _, header := range baseHeaders {
2014			if !slices.ContainsFunc(proxySetHeaders, func(h http.Header) bool {
2015				return header.Name == h.Name
2016			}) {
2017				proxySetHeaders = append(proxySetHeaders, header)
2018			}
2019		}
