2106	// findOIDCProviders returns all unique OIDCProviders referenced across the path rules, de-duped by provider name.
2107	func findOIDCProviders(pathRules []dataplane.PathRule) []*dataplane.OIDCProvider {
2108		seen := make(map[string]struct{})
2109		var providers []*dataplane.OIDCProvider
2110		for _, rule := range pathRules {
2111			for _, matchRule := range rule.MatchRules {
2112				if matchRule.Filters.AuthenticationFilter == nil ||
2113					matchRule.Filters.AuthenticationFilter.OIDC == nil ||
2114					matchRule.Filters.AuthenticationFilter.OIDC.Provider == nil {
2115					continue
2116				}
2117				provider := matchRule.Filters.AuthenticationFilter.OIDC.Provider
2118				if _, exists := seen[provider.Name]; !exists {
2119					seen[provider.Name] = struct{}{}
2120					providers = append(providers, provider)
2121				}
2122			}
2123		}
2124		return providers
2125	}
