2127	// createOIDCLocations creates redirect, logout, and front-channel logout locations for all OIDC providers.
2128	// A location is only created for path-only URIs (starting with /). A location is skipped if an exact-match
2129	// route already occupies the same path or if the location has already been generated. These OIDC
2130	// locations use exact nginx matches, so they safely take precedence over any prefix route.
2131	func createOIDCLocations(pathRules []dataplane.PathRule) []http.Location {
2132		existingExact := existingExactPathSet(pathRules)
2133	
2134		var locs []http.Location
2135		seenPaths := make(map[string]struct{})
2136		for _, provider := range findOIDCProviders(pathRules) {
2137			paths := make([]string, 0, 3)
2138			if strings.HasPrefix(provider.RedirectURI, "/") {
