2141			if provider.LogoutURI != nil {
2142				paths = append(paths, *provider.LogoutURI)
2143			}
2144			if provider.FrontChannelLogoutURI != nil {
2145				paths = append(paths, *provider.FrontChannelLogoutURI)
2146			}
2147	
2148			for _, path := range paths {
2149				if _, exists := existingExact[path]; !exists {
2150					if _, seen := seenPaths[path]; !seen {
2151						seenPaths[path] = struct{}{}
2152						locs = append(locs, createOIDCCallbackLocation(provider, path))
2153					}
2154				}
2155			}
2156		}
2157		return locs
2158	}
