        {{- else }}
          {{- if $.IPFamily.IPv4 }}
    listen {{ $s.Listen }}{{ $.RewriteClientIP.ProxyProtocol }};
          {{- end }}
          {{- if $.IPFamily.IPv6 }}
    listen [::]:{{ $s.Listen }}{{ $.RewriteClientIP.ProxyProtocol }};
