        proxy_set_header {{ .Name }} {{ .Value }};
                {{- end }}
            {{- end }}
        {{- end }}
        {{- end }}

        {{- if $l.AuthJWT }}
        auth_jwt "{{ $l.AuthJWT.Realm }}";
            {{- if $l.AuthJWT.Remote }}
        auth_jwt_key_request {{ $l.AuthJWT.Remote.Path }};
