	return invalidBackendRef
}

// percentOf returns the percentage of a weight out of a totalWeight.
// The percentage is rounded to 2 decimal places using the Floor method.
// Floor is used here in order to guarantee that the sum of all percentages does not exceed 100.
// Ex. percentOf(2, 3) = 66.66
// Ex. percentOf(800, 2000) = 40.00.
func percentOf(weight, totalWeight int32) float64 {
	p := (float64(weight) * 100) / float64(totalWeight)
	return math.Floor(p*100) / 100
}

func backendGroupNeedsSplit(group dataplane.BackendGroup) bool {
	return len(group.Backends) > 1
}

// backendGroupName returns the name of the backend group.
// If the group needs to be split, the name returned is the group name.
// If the group doesn't need to be split, the name returned is the name of the backend if it is valid.
// If the name cannot be determined, it returns the name of the invalid backend upstream.
func backendGroupName(group dataplane.BackendGroup) string {
	switch len(group.Backends) {
	case 0:
		return invalidBackendRef
	case 1:
		b := group.Backends[0]
		if b.Weight == 0 || !b.Valid {
			return invalidBackendRef
		}
		return b.UpstreamName
	default:
		return group.Name()
	}
}

package config

import (
	"fmt"
	"strings"
)

// NGINX Variable names cannot have hyphens.
// This function converts a hyphenated string to an underscored string.
func convertStringToSafeVariableName(s string) string {
	return strings.ReplaceAll(s, "-", "_")
}

// generateAddHeaderMapVariableName Generate the variable name for a proxy add header map.
// We have increased the proxy_headers_hash_bucket_size and variables_hash_bucket_size to 512; and
// proxy_headers_hash_max_size and variables_hash_max_size to 1024 to support the longest header name as allowed
// by the schema (256 characters). This ensures NGINX will not fail to reload.
// FIXME(ciarams87): Investigate if any there are any performance related concerns with changing these directives.
// https://github.com/nginx/nginx-gateway-fabric/issues/772
func generateAddHeaderMapVariableName(name string) string {
	return strings.ToLower(convertStringToSafeVariableName(name)) + "_header_var"
}

func generateCORSAllowedOriginVariableName(serverID string, pathRuleIndex, matchRuleIndex int) string {
	return fmt.Sprintf("$cors_allowed_origin_server%s_path%d_match%d", serverID, pathRuleIndex, matchRuleIndex)
}

func generateCORSAllowCredentialsVariableName(serverID string, pathRuleIndex, matchRuleIndex int) string {
	return fmt.Sprintf("$cors_allow_credentials_server%s_path%d_match%d", serverID, pathRuleIndex, matchRuleIndex)
}

